class OAuthRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for the OAuth server."""

    server: "OAuthHTTPServer"

    def do_GET(self):
        parsed = urllib.parse.urlparse(self.path)
        params = dict(urllib.parse.parse_qsl(parsed.query))

        if parsed.path == "/authorize":
            self._handle_authorize(params)
        else:
            self._send_json(404, {"error": "not_found"})

    def do_POST(self):
        parsed = urllib.parse.urlparse(self.path)

        content_length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(content_length).decode("utf-8")
        params = dict(urllib.parse.parse_qsl(body))

        if parsed.path == "/token":
            self._handle_token(params)
        elif parsed.path == "/introspect":
            self._handle_introspect(params)
        else:
            self._send_json(404, {"error": "not_found"})

    def _handle_authorize(self, params: dict):
        result = self.server.oauth_server.authorize(
            client_id=params.get("client_id", ""),
            redirect_uri=params.get("redirect_uri", ""),
            response_type=params.get("response_type", ""),
            scope=params.get("scope", ""),
            state=params.get("state"),
            code_challenge=params.get("code_challenge"),
            code_challenge_method=params.get("code_challenge_method"),
        )

        if "error" in result:
            if result["error"] == "invalid_redirect_uri":
                # Do NOT redirect - display error directly
                self._send_json(400, result)
            elif "redirect_uri" in result:
                redirect = self._build_error_redirect(
                    result["redirect_uri"],
                    result["error"],
                    result.get("error_description", ""),
                    result.get("state"),
                )
                self._send_redirect(redirect)
            else:
                self._send_json(400, result)
        else:
            # Build redirect with code
            redirect_uri = result["redirect_uri"]
            query_params = {"code": result["code"]}
            if result.get("state"):
                query_params["state"] = result["state"]

            separator = "&" if "?" in redirect_uri else "?"
            redirect = redirect_uri + separator + urllib.parse.urlencode(query_params)
            self._send_redirect(redirect)

    def _handle_token(self, params: dict):
        result = self.server.oauth_server.token_exchange(
            grant_type=params.get("grant_type", ""),
            code=params.get("code", ""),
            redirect_uri=params.get("redirect_uri", ""),
            client_id=params.get("client_id", ""),
            client_secret=params.get("client_secret"),
            code_verifier=params.get("code_verifier"),
        )

        if "error" in result:
            self._send_json(400, result)
        else:
            self._send_json(200, result)

    def _handle_introspect(self, params: dict):
        token = params.get("token", "")
        result = self.server.oauth_server.validate_token(token)
        if result:
            result["active"] = True
            self._send_json(200, result)
        else:
            self._send_json(200, {"active": False})

    @staticmethod
    def _build_error_redirect(
        redirect_uri: str, error: str, description: str, state: Optional[str]
    ) -> str:
        params = {"error": error}
        if description:
            params["error_description"] = description
        if state:
            params["state"] = state
        separator = "&" if "?" in redirect_uri else "?"
        return redirect_uri + separator + urllib.parse.urlencode(params)

    def _send_json(self, status: int, data: dict):
        body = json.dumps(data).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json;charset=UTF-8")
        self.send_header("Cache-Control", "no-store")
        self.send_header("Pragma", "no-cache")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def _send_redirect(self, location: str):
        self.send_response(302)
        self.send_header("Location", location)
        self.send_header("Cache-Control", "no-store")
        self.send_header("Pragma", "no-cache")
        self.end_headers()

    def log_message(self, format, *args):
        logger.info(format, *args)


class OAuthHTTPServer(HTTPServer):
    def __init__(self, server_address, handler_class, oauth_server):
        self.oauth_server = oauth_server
        super().__init__(server_address, handler_class)


